mapper.select:
select
	t1.id                             ,
	t1.manifest_one_and               ,
	t1.attribute_12                   ,
	t1.manifest_posen                 ,
	t1.attribute_11                   ,
	t1.manifest_issue                 ,
	t1.attribute_10                   ,
	t1.last_update_date               ,
	t1.manifest_date_end              ,
	t1.created_dept                   ,
	t1.last_update_ip                 ,
	t1.manifest_leadership            ,
	t1.created_by                     ,
	t1.attribute_04                   ,
	t1.last_updated_by                ,
	t1.attribute_03                   ,
	t1.attribute_02                   ,
	t1.attribute_01                   ,
	t1.manifest_measure               ,
	t1.creation_date                  ,
	t1.manifest_cause                 ,
	t1.attribute_09                   ,
	t1.attribute_08                   ,
	t1.attribute_07                   ,
	t1.attribute_06                   ,
	t1.attribute_05                   ,
	t1.list_mainly                    ,
	t1.manifest_issue_cont            ,
	t1.version                        ,
	t1.org_identity                   ,
	t1.manifest_qian                  
from dyn_task_checklist 	t1


			and t1.ID =#{id}


			and t1.MANIFEST_ONE_AND =#{manifestOneAnd}


			and t1.ATTRIBUTE_12 =#{attribute12}


			and t1.MANIFEST_POSEN =#{manifestPosen}


			and t1.ATTRIBUTE_11 =#{attribute11}


			and t1.MANIFEST_ISSUE =#{manifestIssue}


			and t1.ATTRIBUTE_10 =#{attribute10}


			and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


			and t1.MANIFEST_DATE_END >= #{manifestDateEndBegin}


			and t1.MANIFEST_DATE_END <= #{manifestDateEndEnd}


			and t1.CREATED_DEPT =#{createdDept}


			and t1.LAST_UPDATE_IP =#{lastUpdateIp}


			and t1.MANIFEST_LEADERSHIP =#{manifestLeadership}


			and t1.CREATED_BY =#{createdBy}


			and t1.ATTRIBUTE_04 =#{attribute04}


			and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


			and t1.ATTRIBUTE_03 =#{attribute03}


			and t1.ATTRIBUTE_02 =#{attribute02}


			and t1.ATTRIBUTE_01 =#{attribute01}


			and t1.MANIFEST_MEASURE =#{manifestMeasure}


			and t1.CREATION_DATE =#{creationDate}


			and t1.MANIFEST_CAUSE =#{manifestCause}


			and t1.ATTRIBUTE_09 =#{attribute09}


			and t1.ATTRIBUTE_08 =#{attribute08}


			and t1.ATTRIBUTE_07 =#{attribute07}


			and t1.ATTRIBUTE_06 =#{attribute06}


			and t1.ATTRIBUTE_05 =#{attribute05}


			and t1.LIST_MAINLY =#{listMainly}


			and t1.MANIFEST_ISSUE_CONT =#{manifestIssueCont}


			and t1.VERSION =#{version}


			and t1.ORG_IDENTITY =#{orgIdentity}


			and t1.MANIFEST_QIAN =#{manifestQian}

SELECT t2.id FROM DYN_TASK_CHECKLIST t1 
left join DYN_INSPECTION t2 on t1.id = t2.ATTRIBUTE_03 
 where t1.id =#{id}

select tt.end_,tt.OP_UNAME_,tt.MESSAGE_ from (select MAX(END_) as end_ from ${HashId}  
where current_acti_name_ =#{task} and hproci_= #{entryid} 
and (OP_UNAME_!=null or OP_UNAME_ is not null) 
and (END_!=null or END_ is not null)  
group by  OP_UNAME_  order by END_ desc) t left join ${HashId} tt on tt.END_=t.end_
